# Internal Tooling with Native PostgreSQL Integration

A comprehensive guide to building internal tools that leverage PostgreSQL's native capabilities.

## 1. **Architecture Overview**

```typescript
// Core architecture pattern
interface InternalToolConfig {
  database: {
    connection: PostgresConnection;
    pooling: PoolConfig;
    monitoring: MetricsCollector;
  };
  tools: {
    queryBuilder: QueryBuilder;
    dataExporter: DataExporter;
    autoCompleter: AutoCompleter;
  };
  security: {
    rbac: RoleBasedAccessControl;
    auditLog: AuditLogger;
  };
}

class InternalToolPlatform {
  private db: Pool;
  private queryCache: Map<string, CacheEntry>;
  private auditLog: AuditLogger;

  constructor(config: InternalToolConfig) {
    this.db = this.initializePool(config);
    this.setupMonitoring(config);
    this.initializeAuditLog(config);
  }

  private initializePool(config: InternalToolConfig): Pool {
    return new Pool({
      host: config.database.connection.host,
      port: config.database.connection.port,
      database: config.database.connection.database,
      user: config.database.connection.user,
      password: config.database.connection.password,
      max: config.database.pooling.maxConnections,
      idleTimeoutMillis: config.database.pooling.idleTimeout,
      connectionTimeoutMillis: config.database.pooling.connectionTimeout,
      application_name: 'internal-tooling',
    });
  }
}
```

## 2. **Query Builder with PostgreSQL Features**

```typescript
class PostgreSQLQueryBuilder {
  private query: string = '';
  private params: any[] = [];
  private paramIndex: number = 0;

  // Full-text search with ranking
  fullTextSearch(
    table: string,
    searchColumns: string[],
    query: string,
    language: string = 'english'
  ): this {
    const tsVector = searchColumns
      .map(col => `to_tsvector('${language}', ${col})`)
      .join(' || ');

    const tsQuery = `plainto_tsquery('${language}', $${++this.paramIndex})`;
    this.params.push(query);

    this.query += `
      SELECT *, 
             ts_rank(${tsVector}, ${tsQuery}) as rank
      FROM ${table}
      WHERE ${tsVector} @@ ${tsQuery}
      ORDER BY rank DESC
    `;

    return this;
  }

  // JSON operators and functions
  jsonQuery(jsonColumn: string, path: string[], operator: 'contains' | 'equals'): this {
    const pathStr = path.join(',');

    switch (operator) {
      case 'contains':
        this.query += `WHERE ${jsonColumn} @> $${++this.paramIndex}::jsonb`;
        break;
      case 'equals':
        this.query += `WHERE ${jsonColumn}#>>'{${pathStr}}' = $${++this.paramIndex}`;
        break;
    }

    return this;
  }

  // Range queries with PostgreSQL range types
  rangeQuery(
    column: string,
    minValue: any,
    maxValue: any,
    inclusive: boolean = true
  ): this {
    const operator = inclusive ? '@>' : '-|-';
    this.query += `WHERE ${column}::${this.inferRangeType()} ${operator} 
                   int4range($${++this.paramIndex}, $${++this.paramIndex})`;
    this.params.push(minValue, maxValue);

    return this;
  }

